+/// Check if a query string contains boolean operators
+fn has_boolean_operators(query: &str) -> bool {
+    let tokens = parse_boolean_query(query);
+    tokens.iter().any(|t| {
+        matches!(
+            t,
+            QueryToken::And | QueryToken::Or | QueryToken::Not | QueryToken::Phrase(_)
+        )
+    })
+}
